mapper.select:
/* id="findInventoryListItems" */
 SELECT *
   FROM (    SELECT *
               FROM (    SELECT ROWNUM AS rn
                               ,temp.*
                           FROM (    SELECT STORE_ID
                                           ,MATERIAL_ID
                                           ,I.CURRENT_QUANTITY
                                           ,I.SAFETY_QUANTITY
                                           ,I.CREATED_BY
                                           ,I.CREATED_AT
                                           ,I.UPDATED_BY
                                           ,I.UPDATED_AT
                                           ,S.STORE_NAME
                                           ,M.MATERIAL_NAME
                                       FROM STORE_INVENTORIES I
                                       JOIN MATERIALS M
                                      USING (MATERIAL_ID)
                                       JOIN STORES S
                                      USING (STORE_ID)


        STORE_ID = #{condition.storeId}


            AND MATERIAL_ID = #{condition.materialId}


            AND MATERIAL_NAME = #{condition.materialName}


            AND MATERIAL_TYPE = #{condition.materialType}


            AND CURRENT_QUANTITY < SAFETY_QUANTITY


                                    ORDER BY CREATED_AT DESC
                                           ,STORE_INVENTORY_ID DESC
                                ) temp
                          WHERE ROWNUM  <= #{paging.endRow}
                    )
              WHERE rn >= #{paging.startRow}
        )
